// (issue.defaultPerPage не экспортирован): нужно то же число, чтобы верно
// посчитать totalPages для ссылок пагинации.
const issuesPerPage = 25

// IssueRow — issue вместе с уже построенным SVG-спарклайном. Спарклайн
